    class PacketRequest_MemRead:
        message_id = Types.u16(1)

        def __init__(self, addr, length):
            self.addr = Types.addr_t(addr)
            self.length = Types.size_t(length)

        def __repr__(self):
            return f'PacketRequest_MemRead(message_id={self.message_id}, addr={self.addr}, length={self.length})'

        def __eq__(self, other):
            if type(self) is not type(other):
                return False
            return (self.message_id == other.message_id) and (self.addr == other.addr) and (self.length == other.length)

        def __str__(self):
            return f'<{repr(self)}>'

        def serialize(self) -> bytes:
            buffer = memoryview(bytearray(8))
            buffer[0:2] = Types.u16.serialize(self.message_id)
            buffer[2:6] = Types.addr_t.serialize(self.addr)
            buffer[6:8] = Types.size_t.serialize(self.length)
            return bytes(buffer)

        @classmethod
        def deserialize(cls, data):
            message_id = Types.u16.deserialize(data[0:2])
            assert message_id == int(1)
            addr = Types.addr_t.deserialize(data[2:6])
            length = Types.size_t.deserialize(data[6:8])
            return cls(addr, length)

        @classmethod
        def expected_length(cls, source):
            return 8

        def is_response_to(self, request: _PacketType) -> bool:
            return False

        def is_event_of(self, request: _PacketType) -> bool:
            return False

        @property
        def associated_events(self):
            return tuple()

    class PacketResponse_MemRead:
        message_id = Types.u16(2)

        def __init__(self, result, length, data):
            self.result = Types.IOResult(result)
            self.length = Types.size_t(length)
            self.data = list([Types.u8(x) for x in data])

        def __repr__(self):
            return f'PacketResponse_MemRead(message_id={self.message_id}, result={self.result}, length={self.length}, data={self.data})'

        def __eq__(self, other):
            if type(self) is not type(other):
                return False
            return (self.message_id == other.message_id) and (self.result == other.result) and (self.length == other.length) and (self.data == other.data)

        def __str__(self):
            return f'<{repr(self)}>'

        def serialize(self) -> bytes:
            vla_data = serialize_array(self.data, Types.u8)
            assert len(vla_data) == getattr(self, 'length')
            buffer = memoryview(bytearray(5+len(vla_data)))
            buffer[0:2] = Types.u16.serialize(self.message_id)
            buffer[2:3] = Types.IOResult.serialize(self.result)
            buffer[3:5] = Types.size_t.serialize(self.length)
            buffer[5:5+len(vla_data)] = serialize_array(self.data, Types.u8)
            return bytes(buffer)

        @classmethod
        def deserialize(cls, data):
            message_id = Types.u16.deserialize(data[0:2])
            assert message_id == int(2)
            result = Types.IOResult.deserialize(data[2:3])
            length = Types.size_t.deserialize(data[3:5])
            data = deserialize_array(Types.u8, data[5:])
            return cls(result, length, data)

        @classmethod
        def expected_length(cls, source):
            return 5 + getattr(source, 'length', 0)

        def is_response_to(self, request: _PacketType) -> bool:
            return isinstance(request, PacketTypes.PacketRequest_MemRead)

        def is_event_of(self, request: _PacketType) -> bool:
            return False

